describe('loadConfig', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    jest.resetModules();
    process.env = { ...originalEnv };
  });

  afterAll(() => {
    process.env = originalEnv;
  });

  it('returns config when all required env vars are set', async () => {
    process.env.PORT = '4000';
    process.env.NODE_ENV = 'test';
    process.env.DB_HOST = 'db.local';
    process.env.DB_PORT = '5433';
    process.env.DB_USERNAME = 'user';
    process.env.DB_PASSWORD = 'secret';
    process.env.DB_NAME = 'app';

    const { loadConfig } = await import('../../src/config/env');

    expect(loadConfig()).toEqual({
      port: 4000,
      nodeEnv: 'test',
      database: {
        host: 'db.local',
        port: 5433,
        username: 'user',
        password: 'secret',
        database: 'app',
      },
    });
  });

  it('falls back to defaults for optional values', async () => {
    delete process.env.PORT;
    delete process.env.NODE_ENV;
    delete process.env.DB_PORT;
    process.env.DB_HOST = 'db.local';
    process.env.DB_USERNAME = 'user';
    process.env.DB_PASSWORD = 'secret';
    process.env.DB_NAME = 'app';

    const { loadConfig } = await import('../../src/config/env');

    const config = loadConfig();

    expect(config.port).toBe(3000);
    expect(config.nodeEnv).toBe('development');
    expect(config.database.port).toBe(5432);
  });

  it('throws when a required database variable is missing', async () => {
    process.env.DB_HOST = 'db.local';
    process.env.DB_USERNAME = 'user';
    process.env.DB_PASSWORD = 'secret';
    delete process.env.DB_NAME;

    const { loadConfig } = await import('../../src/config/env');

    expect(() => loadConfig()).toThrow(/DB_NAME/);
  });
});

