describe('buildDataSourceOptions', () => {
  const originalEnv = process.env;

  beforeEach(() => {
    jest.resetModules();
    process.env = { ...originalEnv };
    process.env.DB_HOST = 'db.local';
    process.env.DB_PORT = '5433';
    process.env.DB_USERNAME = 'user';
    process.env.DB_PASSWORD = 'secret';
    process.env.DB_NAME = 'app';
  });

  afterAll(() => {
    process.env = originalEnv;
  });

  it('builds postgres options from env config', async () => {
    process.env.NODE_ENV = 'production';

    const { buildDataSourceOptions } = await import('../src/data-source');

    expect(buildDataSourceOptions()).toMatchObject({
      type: 'postgres',
      host: 'db.local',
      port: 5433,
      username: 'user',
      password: 'secret',
      database: 'app',
      synchronize: false,
      logging: false,
    });
  });

  it('enables logging in development', async () => {
    process.env.NODE_ENV = 'development';

    const { buildDataSourceOptions } = await import('../src/data-source');

    expect(buildDataSourceOptions().logging).toBe(true);
  });
});

